from itertools import combinations
def a(n):
    elements = list(range(1, n+1))
    count = 0
    for r in range(n+1):
        for S in combinations(elements, r):
            S_set = set(S)
            convex = True
            for x in S_set:
                for y in S_set:
                    if x < y and y % x == 0:
                        for z in elements:
                            if z not in S_set and z % x == 0 and y % z == 0:
                                convex = False
                                break
                    if not convex: break
                if not convex: break
            if convex: count += 1
    return count
